//! kaiju-encode-tensor — encode one raw-f32 tensor into a KAIJU1 blob.
//!
//! One stage of the full-model KAIJU1 pipeline (K3c): a python driver
//! extracts f16 tensors + per-tensor imatrix H, this bin does the
//! Leech-heavy encode (rayon over rows), the driver assembles the knot.
//!
//! Usage:
//!   kaiju-encode-tensor --f32 W.f32 --h H.f32 --rows R --cols C \
//!     --out enc.kaiju1 [--hi-frac 0.10] [--fisher-steps 0]
//!
//! `--fisher-steps K` (default 0) enables the Fisher-weighted bulk step search:
//! K=0 is the legacy unweighted-RMS step (byte-identical); K≥1 picks each bulk
//! block's step to minimize `Σ Hᵢ(ΔWᵢ)²` in a ±K multiplier window. Cost scales
//! ~(2K+1)× the bulk `nearest_leech` calls.
//!
//! Prints one JSON line of telemetry: bytes, bpw, clamp rate, fisher_steps.

use std::collections::HashMap;
use std::fs;
use std::io::Write as _;

use distributed_inference::kaiju_format::encode_kaiju1;

fn parse_args() -> HashMap<String, String> {
    let mut out = HashMap::new();
    let args: Vec<String> = std::env::args().collect();
    let mut i = 1;
    while i + 1 < args.len() {
        if let Some(key) = args[i].strip_prefix("--") {
            out.insert(key.to_string(), args[i + 1].clone());
            i += 2;
        } else {
            i += 1;
        }
    }
    out
}

fn read_f32(path: &str, expect: usize) -> Result<Vec<f32>, String> {
    let raw = fs::read(path).map_err(|e| format!("read {path}: {e}"))?;
    if raw.len() != expect * 4 {
        return Err(format!("{path}: {} bytes, expected {}", raw.len(), expect * 4));
    }
    Ok(raw
        .chunks_exact(4)
        .map(|c| f32::from_le_bytes([c[0], c[1], c[2], c[3]]))
        .collect())
}

fn main() -> Result<(), String> {
    let args = parse_args();
    let rows: usize = args.get("rows").and_then(|s| s.parse().ok()).ok_or("--rows")?;
    let cols: usize = args.get("cols").and_then(|s| s.parse().ok()).ok_or("--cols")?;
    let hi_frac: f64 = args.get("hi-frac").and_then(|s| s.parse().ok()).unwrap_or(0.10);
    let fisher_steps: usize = args
        .get("fisher-steps")
        .and_then(|s| s.parse().ok())
        .unwrap_or(0);
    let w = read_f32(args.get("f32").ok_or("--f32")?, rows * cols)?;
    let h = read_f32(args.get("h").ok_or("--h")?, cols)?;

    let (bytes, clamp) = encode_kaiju1(&w, rows, cols, &h, hi_frac, fisher_steps);
    let out_path = args.get("out").ok_or("--out")?;
    let mut f = fs::File::create(out_path).map_err(|e| e.to_string())?;
    f.write_all(&bytes).map_err(|e| e.to_string())?;
    println!(
        "{{\"bytes\":{},\"bpw\":{:.4},\"clamp\":{:.5},\"fisher_steps\":{}}}",
        bytes.len(),
        bytes.len() as f64 * 8.0 / (rows * cols) as f64,
        clamp,
        fisher_steps
    );
    Ok(())
}
